module watchdog_timer(  
    input wire clk,  
    input wire reset,  
    input wire [3:0] timeout_limit,  
    output reg system_reset  
);  
    reg [3:0] cycle_count;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            cycle_count <= 4'd0;  
            system_reset <= 1'b0;  
        end else begin  
            if (cycle_count < timeout_limit) begin  
                cycle_count <= cycle_count + 1;  
                system_reset <= 1'b0;  
            end else begin  
                system_reset <= 1'b1;  
            end  
        end  
    end  
endmodule
